import{_ as a,o as t,c as i,ag as l}from"./chunks/framework.CnqOxlWO.js";const p=JSON.parse('{"title":"Agent Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"features/agent-config.md","filePath":"features/agent-config.md","lastUpdated":1773376681000}'),n={name:"features/agent-config.md"};function o(s,e,r,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="agent-configuration" tabindex="-1">Agent Configuration <a class="header-anchor" href="#agent-configuration" aria-label="Permalink to &quot;Agent Configuration&quot;">​</a></h1><p>The Agent Detail page is the central configuration hub for each agent.</p><p>To open it, hover over an agent in the sidebar and click the <strong>Settings</strong> icon.</p><h2 id="overview-panel" tabindex="-1">Overview Panel <a class="header-anchor" href="#overview-panel" aria-label="Permalink to &quot;Overview Panel&quot;">​</a></h2><p>At the top of the page, a summary panel shows the agent&#39;s key stats:</p><ul><li>Current model</li><li>Channel connection status</li><li>Number of sessions</li><li>Number of DM sessions</li><li>Message count</li><li>Token usage</li><li>Last active time</li><li>Average response time</li></ul><p>Use this panel to quickly assess whether the agent is operational.</p><h2 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;Model&quot;">​</a></h2><p>The Model tab controls which AI model powers the agent&#39;s responses.</p><h3 id="what-you-see" tabindex="-1">What You See <a class="header-anchor" href="#what-you-see" aria-label="Permalink to &quot;What You See&quot;">​</a></h3><ul><li>Whether a model is currently assigned</li><li>Which model is in use</li><li>A button to pick or change the model</li></ul><h3 id="how-to-configure" tabindex="-1">How to Configure <a class="header-anchor" href="#how-to-configure" aria-label="Permalink to &quot;How to Configure&quot;">​</a></h3><ol><li>Go to the <strong>Model</strong> tab.</li><li>Click <strong>Pick Platform Model</strong> (or <strong>Change Model</strong> if one is already set).</li><li>In the dialog, select a model from the available list.</li><li>Wait for the configuration to save.</li></ol><p>The model picker dialog shows:</p><ul><li>Model name and provider</li><li>Input price</li><li>Output price</li><li>Credit cost</li><li>A brief description</li></ul><h3 id="when-to-check-this-first" tabindex="-1">When to Check This First <a class="header-anchor" href="#when-to-check-this-first" aria-label="Permalink to &quot;When to Check This First&quot;">​</a></h3><p>If the agent was created successfully but does not respond to messages, this is the first place to look. An agent without a model cannot generate replies.</p><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h2><p>The Skills tab has two sections:</p><h3 id="agent-skills" tabindex="-1">Agent Skills <a class="header-anchor" href="#agent-skills" aria-label="Permalink to &quot;Agent Skills&quot;">​</a></h3><p>Skills that are installed specifically on this agent.</p><p>You can:</p><ul><li>View installed skills</li><li>Open a skill&#39;s detail dialog (description, configuration, README)</li><li>Uninstall skills you no longer need</li><li>Search the marketplace and install new skills</li></ul><h3 id="built-in-skills" tabindex="-1">Built-in Skills <a class="header-anchor" href="#built-in-skills" aria-label="Permalink to &quot;Built-in Skills&quot;">​</a></h3><p>Global skills that ship with the application.</p><p>You can:</p><ul><li>View each skill&#39;s description</li><li>Enable or disable individual built-in skills</li></ul><p>If you are unsure whether to enable a skill, keep the defaults and add skills as needed.</p><h2 id="channels" tabindex="-1">Channels <a class="header-anchor" href="#channels" aria-label="Permalink to &quot;Channels&quot;">​</a></h2><p>The Channels tab connects the agent to external messaging platforms.</p><h3 id="what-you-can-do" tabindex="-1">What You Can Do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to &quot;What You Can Do&quot;">​</a></h3><ul><li>View connected channels and their status</li><li>Add a new channel</li><li>Remove an existing channel</li></ul><h3 id="telegram-setup" tabindex="-1">Telegram Setup <a class="header-anchor" href="#telegram-setup" aria-label="Permalink to &quot;Telegram Setup&quot;">​</a></h3><p>Click <strong>Add Channel</strong>, then select Telegram. You need to fill in:</p><ul><li><strong>Bot Token</strong> — obtained from Telegram&#39;s <code>@BotFather</code></li><li><strong>Allowed Users</strong> — a comma-separated list of Telegram usernames (without the <code>@</code> prefix)</li></ul><p>To allow all users, enter <code>*</code>.</p><p>After saving, the app validates the token automatically. On success, the bot&#39;s username appears and the channel is added to the list.</p><p>For a detailed walkthrough, see <a href="/clawdsaber-docs/features/telegram.html">Telegram Integration</a>.</p><h2 id="soul" tabindex="-1">SOUL <a class="header-anchor" href="#soul" aria-label="Permalink to &quot;SOUL&quot;">​</a></h2><p>The SOUL tab defines the agent&#39;s personality and long-term behavior.</p><p>Think of it as the system prompt that shapes how the agent responds across all conversations.</p><h3 id="what-you-can-do-1" tabindex="-1">What You Can Do <a class="header-anchor" href="#what-you-can-do-1" aria-label="Permalink to &quot;What You Can Do&quot;">​</a></h3><ul><li>Edit the SOUL content directly in the text editor</li><li>Choose a preset template from the template selector</li><li>Save your changes</li></ul><h3 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h3><ul><li>If you are not sure what to write, start with a preset template and modify it.</li><li>Applying a template replaces the current content, so back up anything you want to keep first.</li></ul><h2 id="environment-variables-env" tabindex="-1">Environment Variables (.env) <a class="header-anchor" href="#environment-variables-env" aria-label="Permalink to &quot;Environment Variables (.env)&quot;">​</a></h2><p>The .env tab lets you add runtime variables specific to this agent.</p><p>Use cases include:</p><ul><li>Extra configuration for specific channels or services</li><li>Variables that certain skills need to read</li><li>Settings you want to keep separate from other agents</li></ul><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>This is a plain text editor — one <code>KEY=VALUE</code> per line</li><li>Remember to click <strong>Save</strong> after making changes</li><li>If you are not sure whether a variable will affect behavior, test on a low-risk agent first</li></ul><h2 id="deleting-an-agent" tabindex="-1">Deleting an Agent <a class="header-anchor" href="#deleting-an-agent" aria-label="Permalink to &quot;Deleting an Agent&quot;">​</a></h2><p>You can delete an agent from the overview panel at the top of the Agent Detail page.</p><p>Click the <strong>Delete</strong> button and confirm in the dialog.</p><p>This action is irreversible. Before deleting, consider whether you still need the agent&#39;s SOUL content, <code>.env</code> settings, or channel configurations.</p><h2 id="recommended-configuration-order" tabindex="-1">Recommended Configuration Order <a class="header-anchor" href="#recommended-configuration-order" aria-label="Permalink to &quot;Recommended Configuration Order&quot;">​</a></h2><p>If you just want to get an agent running as quickly as possible:</p><ol><li>Assign a model.</li><li>Send a test message.</li><li>Add skills when you need extended capabilities.</li><li>Add a Telegram channel when you want external access.</li><li>Refine the SOUL and <code>.env</code> over time.</li></ol>',58)])])}const g=a(n,[["render",o]]);export{p as __pageData,g as default};
